1	// Generate CRM Tracker Excel — 客户管理看板
2	// Usage: node scripts/generate-crm-tracker.js
3	// Output: reports/客户管理看板_{date}.xlsx
4	// Auto-classifies all customers into P0-P4 tiers + basic stage detection
5	
6	const fs = require('fs');
7	const path = require('path');
8	const ExcelJS = require('exceljs');
9	
10	const DATA_DIR = path.join(__dirname, '..', 'data');
11	const REPORTS_DIR = path.join(__dirname, '..', 'reports');
12	const TM_FILE = path.join(DATA_DIR, 'tm_conversations_latest.json');
13	const CHAT_DIR = path.join(DATA_DIR, 'chat_history');
14	const CUSTOMERS_DIR = path.join(DATA_DIR, 'customers');
15	const STATE_FILE = path.join(__dirname, '..', 'STATE.md');
16	
17	const NOW = new Date();
18	const DATE_STR = NOW.toISOString().slice(0, 10);
19	const NOW_TS = NOW.getTime();
20	const D = 86400000;
21	
22	// === COUNTRY MAP ===
23	const COUNTRY_CN = {
24	  AF:'阿富汗', AL:'阿尔巴尼亚', DZ:'阿尔及利亚', AO:'安哥拉', AR:'阿根廷', AM:'亚美尼亚', AU:'澳大利亚', AT:'奥地利',
25	  AZ:'阿塞拜疆', BH:'巴林', BD:'孟加拉', BY:'白俄罗斯', BE:'比利时', BJ:'贝宁', BO:'玻利维亚', BA:'波黑',
26	  BW:'博茨瓦纳', BR:'巴西', BG:'保加利亚', BF:'布基纳法索', BI:'布隆迪', KH:'柬埔寨', CM:'喀麦隆', CA:'加拿大',
27	  CL:'智利', CN:'中国', CO:'哥伦比亚', CG:'刚果布', CD:'刚果金', CR:'哥斯达黎加', CI:'科特迪瓦', HR:'克罗地亚',
28	  CU:'古巴', CY:'塞浦路斯', CZ:'捷克', DK:'丹麦', DJ:'吉布提', DO:'多米尼加', EC:'厄瓜多尔', EG:'埃及',
29	  SV:'萨尔瓦多', EE:'爱沙尼亚', ET:'埃塞俄比亚', FI:'芬兰', FR:'法国', GA:'加蓬', GM:'冈比亚', GE:'格鲁吉亚',
30	  DE:'德国', GH:'加纳', GR:'希腊', GT:'危地马拉', GN:'几内亚', GY:'圭亚那', HT:'海地', HN:'洪都拉斯',
31	  HK:'香港', HU:'匈牙利', IS:'冰岛', IN:'印度', ID:'印尼', IR:'伊朗', IQ:'伊拉克', IE:'爱尔兰',
32	  IL:'以色列', IT:'意大利', JM:'牙买加', JP:'日本', JO:'约旦', KZ:'哈萨克斯坦', KE:'肯尼亚', KW:'科威特',
33	  KG:'吉尔吉斯斯坦', LA:'老挝', LV:'拉脱维亚', LB:'黎巴嫩', LY:'利比亚', LT:'立陶宛', LU:'卢森堡', MG:'马达加斯加',
34	  MW:'马拉维', MY:'马来西亚', ML:'马里', MR:'毛里塔尼亚', MU:'毛里求斯', MX:'墨西哥', MD:'摩尔多瓦', MN:'蒙古',
35	  MA:'摩洛哥', MZ:'莫桑比克', MM:'缅甸', NA:'纳米比亚', NP:'尼泊尔', NL:'荷兰', NZ:'新西兰', NE:'尼日尔',
36	  NG:'尼日利亚', KP:'朝鲜', NO:'挪威', OM:'阿曼', PK:'巴基斯坦', PS:'巴勒斯坦', PA:'巴拿马', PY:'巴拉圭',
37	  PE:'秘鲁', PH:'菲律宾', PL:'波兰', PT:'葡萄牙', QA:'卡塔尔', RO:'罗马尼亚', RU:'俄罗斯', RW:'卢旺达',
38	  SA:'沙特阿拉伯', SN:'塞内加尔', RS:'塞尔维亚', SC:'塞舌尔', SL:'塞拉利昂', SG:'新加坡', SK:'斯洛伐克',
39	  SI:'斯洛文尼亚', SO:'索马里', ZA:'南非', KR:'韩国', SS:'南苏丹', ES:'西班牙', LK:'斯里兰卡', SD:'苏丹',
40	  SR:'苏里南', SE:'瑞典', CH:'瑞士', SY:'叙利亚', TW:'台湾', TJ:'塔吉克斯坦', TZ:'坦桑尼亚', TH:'泰国',
41	  TG:'多哥', TT:'特立尼达和多巴哥', TN:'突尼斯', TR:'土耳其', TM:'土库曼斯坦', UG:'乌干达', UA:'乌克兰',
42	  AE:'阿联酋', GB:'英国', US:'美国', UY:'乌拉圭', UZ:'乌兹别克斯坦', VE:'委内瑞拉', VN:'越南', YE:'也门',
43	  ZM:'赞比亚', ZW:'津巴布韦',
44	};
45	
46	function cn(country) {
47	  if (!country) return '';
48	  const c = country.toUpperCase();
49	  return COUNTRY_CN[c] || c;
50	}
51	
52	// === SYSTEM MESSAGE FILTER ===
53	const SYS_PATTERNS = [
54	  '自动接待将不再触发', 'Since you have read the conversation',
55	  'Marco大模型翻译', '阿里国际Marco大模型翻译',
56	  '买家有流失风险', 'Buyer has churn risk',
57	  '一旦离开平台发生纠纷或欺诈', '由于您介入该会话', 'Due to your intervention',
58	  '反馈', 'AI给您生成了一条回复建议',
59	  'You have a visitor', 'This buyer has been pre-screened',
60	  '当前买家首次给您发消息',
61	];
62	
63	function isSystemMsg(content) {
64	  if (!content) return false;
65	  for (const p of SYS_PATTERNS) {
66	    if (content.includes(p)) return true;
67	  }
68	  return false;
69	}
70	
71	// === TIER CLASSIFICATION (from business-rules.md + system-prompt.md) ===
72	function classifyTier(conv, msgCount) {
73	  const daysAgo = conv.lastContactTime ? Math.floor((NOW_TS - conv.lastContactTime) / D) : 9999;
74	  const isUnread = conv.unreadCount > 0;
75	  const latestContent = conv.latestMessage?.content || '';
76	  const latestType = conv.latestMessage?.messageType || '';
77	  const isSys = isSystemMsg(latestContent);
78	  // Core markets (higher priority)
79	  const coreMarkets = ['SD','EG','CD','ZM','CI','SA','AE'];
80	  const isCore = coreMarkets.includes((conv.complianceCountryCode || '').toUpperCase());
81	
82	  // P0: Immediate action needed
83	  if (isUnread) return 'P0';
84	  if (latestType === 'received' && !isSys && daysAgo < 2) return 'P0';
85	  // PI/payment related signals in latest message
86	  const piKeywords = ['PI','Proforma','Invoice','payment','付款','deposit','定金','Wire Transfer','TT','bank transfer'];
87	  if (piKeywords.some(k => latestContent.toLowerCase().includes(k.toLowerCase())) && daysAgo < 7) return 'P0';
88	  if (msgCount > 50 && daysAgo < 2 && latestType === 'received') return 'P0';
89	
90	  // P1: Active this week
91	  if (daysAgo < 7 && msgCount >= 5) return 'P1';
92	  if (daysAgo < 3 && msgCount >= 3 && latestType === 'received' && !isSys) return 'P1';
93	  if (isCore && daysAgo < 14 && msgCount >= 10) return 'P1';
94	
95	  // P2: Recent contact but not deep
96	  if (daysAgo < 7) return 'P2';
97	  if (msgCount > 20 && daysAgo < 14) return 'P2';
98	
99	  // P3: Low activity, within 30 days
100	  if (daysAgo < 30) return 'P3';
101	
102	  // P4: Silent
103	  return 'P4';
104	}
105	
106	// === STAGE DETECTION ===
107	function detectStage(conv, msgCount) {
108	  const latestContent = conv.latestMessage?.content || '';
109	  const latestType = conv.latestMessage?.messageType || '';
110	  const daysAgo = conv.lastContactTime ? Math.floor((NOW_TS - conv.lastContactTime) / D) : 9999;
111	  const content = latestContent.toLowerCase();
112	
113	  if (daysAgo > 30 && msgCount <= 3) return '沉默-无有效对话';
114	
115	  const piKw = ['pi','proforma','invoice','payment','付款','deposit','定金','tt ','wire transfer','bank transfer','sent you the','quote sent'];
116	  if (piKw.some(k => content.includes(k))) {
117	    if (latestType === 'send') return 'PI已发-等付款';
118	    if (latestType === 'received') return '付款确认中';
119	  }
120	
121	  const negotiateKw = ['price','quote','quotation','cost','sample','样品','ship','freight','运费','moq','数量','order','discount','offer'];
122	  if (negotiateKw.some(k => content.includes(k)) && daysAgo < 7) return '谈判中';
123	
124	  if (msgCount <= 5 && daysAgo < 14) return '初询阶段';
125	  if (daysAgo >= 30) return '沉默->30d';
126	  if (daysAgo >= 7 && daysAgo < 30) return '待激活';
127	
128	  return '';
129	}
130	
131	// === HELPERS ===
132	function daysAgoFn(ts) { if (!ts) return 9999; return Math.floor((NOW_TS - ts) / D); }
133	function fmtDate(ts) { if (!ts) return ''; return new Date(ts).toISOString().slice(0, 10); }
134	function cidToFile(cid) { return cid ? cid.replace(/#/g, '_').replace(/@/g, '_') + '.json' : ''; }
135	
136	// === MAIN ===
137	async function main() {
138	  console.log('[CRM Tracker] Reading data...');
139	
140	  // 1. Conversations
141	  if (!fs.existsSync(TM_FILE)) { console.error('tm_conversations_latest.json not found'); process.exit(1); }
142	  const tmData = JSON.parse(fs.readFileSync(TM_FILE, 'utf8'));
143	  const convs = tmData.conversations || [];
144	  console.log(`  ${convs.length} conversations`);
145	
146	  // 2. Customers (name-based lookup)
147	  const customerFiles = fs.readdirSync(CUSTOMERS_DIR).filter(f => f.endsWith('.json'));
148	  const custByName = {};
149	  for (const f of customerFiles) {
150	    try {
151	      const raw = fs.readFileSync(path.join(CUSTOMERS_DIR, f), 'utf8');
152	      const cust = JSON.parse(raw);
153	      const name = (cust.name || cust.detail?.name_info || '').toLowerCase().trim();
154	      if (name) {
155	        custByName[name] = {
156	          okkiLevel: cust.listData?.level || cust.detail?.cus_tag_info?.[0]?.info_label || '',
157	          okkiStatus: cust.listData?.status || cust.detail?.trail_status_info || '',
158	          country: cust.listData?.country || cust.detail?.country || '',
159	          intent: cust.detail?.intention_level_info || '',
160	        };
161	      }
162	    } catch (e) { /* skip */ }
163	  }
164	  console.log(`  ${Object.keys(custByName).length} customer profiles matched`);
165	
166	  // 3. Chat message counts (fast scan)
167	  const chatDirFiles = fs.readdirSync(CHAT_DIR).filter(f => f.endsWith('.json'));
168	  const chatMsgCount = {};
169	  for (const cf of chatDirFiles) {
170	    try {
171	      const raw = fs.readFileSync(path.join(CHAT_DIR, cf), 'utf8');
172	      const match = raw.match(/"totalMessages":\s*(\d+)/);
173	      if (match) chatMsgCount[cf] = parseInt(match[1]);
174	    } catch (e) { /* skip */ }
175	  }
176	
177	  // 4. Existing P0/P1 names from STATE.md for override
178	  const knownP0P1 = new Map();
179	  if (fs.existsSync(STATE_FILE)) {
180	    const sc = fs.readFileSync(STATE_FILE, 'utf8');
181	    const tierSec = sc.match(/\|\s*\*\*(P\d)\*\*[^\n]*\n/g);
182	    if (tierSec) {
183	      for (const line of tierSec) {
184	        const m = line.match(/\*\*(P\d)\*\*\s+\S+\s+\|\s+\*?\*?(\d+)\*?\*?\s*\|?\s*(.+)/);
185	        if (m) {
186	          const tier = m[1];
187	          const names = m[3].split(/[,，、]/);
188	          for (const n of names) {
189	            const trimmed = n.trim().replace(/\(.*\)/g, '').trim();
190	            if (trimmed && !trimmed.startsWith('等') && !/^\d+$/.test(trimmed)) {
191	              knownP0P1.set(trimmed.toLowerCase(), tier);
192	            }
193	          }
194	        }
195	      }
196	    }
197	  }
198	  console.log(`  ${knownP0P1.size} known P0/P1 from STATE.md`);
199	
200	  // 5. Build rows
201	  const rows = [];
202	  for (const conv of convs) {
203	    const filename = cidToFile(conv.cid);
204	    const msgCount = filename ? (chatMsgCount[filename] || 0) : 0;
205	    const nameLow = (conv.name || '').toLowerCase().trim();
206	
207	    // Match customer profile
208	    let cust = custByName[nameLow] || null;
209	    if (!cust) {
210	      for (const [cn, ci] of Object.entries(custByName)) {
211	        if (nameLow.includes(cn) || cn.includes(nameLow)) { cust = ci; break; }
212	      }
213	    }
214	
215	    // Tier: STATE.md overrides auto-classification
216	    let tier = '';
217	    for (const [kn, kv] of knownP0P1) {
218	      if (nameLow.includes(kn) || kn.includes(nameLow)) { tier = kv; break; }
219	    }
220	    if (!tier) tier = classifyTier(conv, msgCount);
221	
222	    // Stage
223	    const stage = detectStage(conv, msgCount);
224	
225	    // Direction
226	    let lastMsgDir = '';
227	    if (conv.latestMessage) {
228	      lastMsgDir = conv.latestMessage.messageType === 'send' ? '我方' : '客户';
229	    }
230	
231	    const d = daysAgoFn(conv.lastContactTime);
232	
233	    rows.push({
234	      name: conv.name || '',
235	      countryCode: conv.complianceCountryCode || '',
236	      countryCN: cn(conv.complianceCountryCode),
237	      tier,
238	      okkiLevel: cust ? cust.okkiLevel : '',
239	      okkiStatus: cust ? cust.okkiStatus : '',
240	      lastContactDays: d,
241	      lastContactDate: fmtDate(conv.lastContactTime),
242	      msgCount,
243	      lastMsgDir,
244	      unreadCount: conv.unreadCount || 0,
245	      stage,
246	      bottleneck: '',
247	      nextAction: '',
248	      followupPriority: tier === 'P0' ? '今天' : tier === 'P1' ? '48h' : tier === 'P2' ? '本周' : '',
249	      notes: cust && cust.intent && cust.intent !== '未知' ? `意向:${cust.intent}` : '',
250	      cid: conv.cid,
251	      filename,
252	    });
253	  }
254	
255	  // Sort: P0 → P1 → P2 → P3 → P4, then by lastContactDays asc within each
256	  const tierOrder = { P0: 0, P1: 1, P2: 2, P3: 3, P4: 4 };
257	  rows.sort((a, b) => {
258	    const ta = tierOrder[a.tier] ?? 5;
259	    const tb = tierOrder[b.tier] ?? 5;
260	    if (ta !== tb) return ta - tb;
261	    return a.lastContactDays - b.lastContactDays;
262	  });
263	
264	  // === GEN EXCEL ===
265	  console.log(`[CRM Tracker] Generating ${rows.length} rows...`);
266	
267	  const wb = new ExcelJS.Workbook();
268	  wb.creator = 'OKKI CRM Tracker';
269	  wb.created = NOW;
270	
271	  const ws = wb.addWorksheet('客户管理看板', { views: [{ state: 'frozen', ySplit: 1 }] });
272	
273	  const cols = [
274	    { header: '客户名', key: 'name', width: 24 },
275	    { header: '国家', key: 'countryCN', width: 12 },
276	    { header: '梯队', key: 'tier', width: 7 },
277	    { header: '小满等级', key: 'okkiLevel', width: 14 },
278	    { header: '小满状态', key: 'okkiStatus', width: 12 },
279	    { header: '最后联系\n(天前)', key: 'lastContactDays', width: 9 },
280	    { header: '最后联系日期', key: 'lastContactDate', width: 13 },
281	    { header: '总消息', key: 'msgCount', width: 8 },
282	    { header: '最新', key: 'lastMsgDir', width: 7 },
283	    { header: '未读', key: 'unreadCount', width: 6 },
284	    { header: '沟通阶段', key: 'stage', width: 18 },
285	    { header: '卡点', key: 'bottleneck', width: 28 },
286	    { header: '下一步行动', key: 'nextAction', width: 34 },
287	    { header: '跟紧', key: 'followupPriority', width: 8 },
288	    { header: '备注', key: 'notes', width: 22 },
289	  ];
290	  ws.columns = cols;
291	
292	  // Header style
293	  const hr = ws.getRow(1);
294	  hr.font = { bold: true, size: 11, color: { argb: 'FFFFFFFF' } };
295	  hr.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FF2F5496' } };
296	  hr.alignment = { vertical: 'middle', horizontal: 'center', wrapText: true };
297	  hr.height = 34;
298	
299	  const tierFills = {
300	    P0: 'FFC00000', P1: 'FFED7D31', P2: 'FFFFC000', P3: 'FF4472C4', P4: 'FFA5A5A5',
301	  };
302	
303	  for (const row of rows) {
304	    const r = ws.addRow(row);
305	    r.height = 21;
306	
307	    // Tier color
308	    if (row.tier && tierFills[row.tier]) {
309	      const tc = r.getCell('tier');
310	      tc.font = { bold: true, color: { argb: 'FFFFFFFF' }, size: 11 };
311	      tc.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: tierFills[row.tier] } };
312	      tc.alignment = { horizontal: 'center' };
313	    }
314	
315	    // Faded for >30d
316	    if (row.lastContactDays > 30) r.font = { color: { argb: 'FFA0A0A0' } };
317	    // Unread highlight
318	    if (row.unreadCount > 0) r.getCell('unreadCount').font = { bold: true, color: { argb: 'FFC00000' } };
319	    // Stage bold
320	    if (row.stage) r.getCell('stage').font = { bold: true };
321	    // P0 name bold
322	    if (row.tier === 'P0') r.getCell('name').font = { bold: true };
323	  }
324	
325	  ws.autoFilter = { from: { row: 1, column: 1 }, to: { row: rows.length + 1, column: cols.length } };
326	
327	  // === SUMMARY SHEET ===
328	  const sws = wb.addWorksheet('统计');
329	  sws.columns = [
330	    { header: '指标', key: 'metric', width: 22 },
331	    { header: '数值', key: 'value', width: 26 },
332	  ];
333	
334	  const tc = { P0: 0, P1: 0, P2: 0, P3: 0, P4: 0, '未分类': 0 };
335	  for (const r of rows) {
336	    if (r.tier && tc[r.tier] !== undefined) tc[r.tier]++;
337	    else tc['未分类']++;
338	  }
339	
340	  const a24 = rows.filter(r => r.lastContactDays < 1).length;
341	  const a7d = rows.filter(r => r.lastContactDays < 7).length;
342	  const a30d = rows.filter(r => r.lastContactDays < 30).length;
343	  const s30d = rows.filter(r => r.lastContactDays >= 30).length;
344	  const withStage = rows.filter(r => r.stage).length;
345	  const withBN = rows.filter(r => r.bottleneck).length;
346	
347	  sws.addRows([
348	    { metric: '生成时间', value: NOW.toISOString().slice(0, 16).replace('T', ' ') },
349	    { metric: '数据导出时间', value: tmData.exportedAt ? new Date(tmData.exportedAt).toISOString().slice(0, 16).replace('T', ' ') : '' },
350	    { metric: '客户总数', value: rows.length },
351	    { metric: '24h活跃', value: a24 },
352	    { metric: '7d活跃', value: a7d },
353	    { metric: '30d内活跃', value: a30d },
354	    { metric: '>30d沉默', value: s30d },
355	    { metric: '', value: '' },
356	    ...Object.entries(tc).map(([k, v]) => ({ metric: `梯队 ${k}`, value: v })),
357	    { metric: '', value: '' },
358	    { metric: '已推断阶段', value: withStage },
359	    { metric: '已标注卡点', value: withBN },
360	    { metric: '待AI深度分析', value: rows.length - withBN },
361	    { metric: '', value: '' },
362	    { metric: '分类规则', value: 'P0=未读/客户最新消息/PI关键词 | P1=7d活跃+≥5条 | P2=7d活跃 | P3=<30d | P4=>30d静默' },
363	  ]);
364	
365	  const sh = sws.getRow(1);
366	  sh.font = { bold: true, color: { argb: 'FFFFFFFF' } };
367	  sh.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FF2F5496' } };
368	
369	  const outFile = path.join(REPORTS_DIR, `客户管理看板_${DATE_STR}.xlsx`);
370	  if (!fs.existsSync(REPORTS_DIR)) fs.mkdirSync(REPORTS_DIR, { recursive: true });
371	  await wb.xlsx.writeFile(outFile);
372	
373	  console.log(`\n[Done] ${outFile}`);
374	  console.log(`  ${rows.length} customers | P0:${tc.P0} P1:${tc.P1} P2:${tc.P2} P3:${tc.P3} P4:${tc.P4}`);
375	  console.log(`  24h:${a24} | 7d:${a7d} | 30d:${a30d} | >30d:${s30d}`);
376	  console.log(`  Stage detected: ${withStage} | Need AI: ${rows.length - withBN}`);
377	}
378	
379	main().catch(err => { console.error(err); process.exit(1); });
380

