const fs = require('fs');
const path = require('path');

const s1 = JSON.parse(fs.readFileSync('data/s1_classification.json', 'utf8'));
const chatDir = 'data/chat_history';
const NOW = Date.now();
const DAY = 86400000;

const SYS_PATTERNS = [
  '自动接待将不再触发', 'Since you have read the conversation',
  'Marco大模型翻译', '阿里国际Marco大模型翻译',
  '买家有流失风险', 'Buyer has churn risk',
  '一旦离开平台发生纠纷或欺诈', '由于您介入该会话', 'Due to your intervention',
  '反馈', 'AI给您生成了一条回复建议',
  'You have a visitor', 'This buyer has been pre-screened',
  '当前买家首次给您发消息',
];

function isSys(content) {
  if (!content) return false;
  for (const p of SYS_PATTERNS) {
    if (content.includes(p)) return true;
  }
  return false;
}

// Get all P1+P2+P3 candidates for enhanced classification
const allCandidates = [...(s1.results[1]||[]), ...(s1.results[2]||[]), ...(s1.results[3]||[])];
console.log('Processing', allCandidates.length, 'candidates (P1+P2+P3)...');
console.log('');

const enhanced = [];

for (const c of allCandidates) {
  const cid = c.cid;
  const filename = cid ? cid.replace(/#/g, '_').replace(/@/g, '_') + '.json' : '';
  const filePath = path.join(chatDir, filename);

  let msgCount = 0, customerMsgs = 0, agentMsgs = 0, sysMsgs = 0;
  let latestRealMsg = { type: '', content: '', date: '' };
  let hasPI = false, hasAddress = false, hasOrderSignal = false, hasPrice = false;
  let hasSample = false, hasFreight = false, hasMOQ = false;

  if (fs.existsSync(filePath)) {
    try {
      const raw = fs.readFileSync(filePath, 'utf8');
      const data = JSON.parse(raw);
      const msgs = data.conversations || data.messages || [];
      msgCount = data.totalMessages || msgs.length || 0;

      for (const msg of msgs) {
        const st = msg.senderType || '';
        const content = (msg.content?.text?.content || msg.content || '').toString();
        if (st === 'customer') customerMsgs++;
        else if (st === 'agent' || st === 'customer_service') agentMsgs++;
        else if (st === 'system') sysMsgs++;

        // Find latest real (non-system) message
        if (!isSys(content) && content.trim().length > 0 && st !== 'system') {
          const msgDate = msg.sendTime || msg.createTime || '';
          if (!latestRealMsg.date || msgDate > latestRealMsg.date) {
            latestRealMsg = { type: st, content: content.substring(0, 120), date: msgDate };
          }
        }

        // Signal detection
        const lc = content.toLowerCase();
        if (/pi|proforma|invoice|付款|deposit|定金/.test(lc)) hasPI = true;
        if (/address|地址|delivery|shipping|country|city/.test(lc) && st === 'customer') hasAddress = true;
        if (/order|下单|place.*order|make.*order|confirm.*order/.test(lc)) hasOrderSignal = true;
        if (/price|报价|quotation|quote|price/.test(lc) && st === 'agent') hasPrice = true;
        if (/sample|样品/.test(lc)) hasSample = true;
        if (/freight|shipping|运费|物流|delivery|transport/.test(lc)) hasFreight = true;
        if (/MOQ|minimum|最低|500/.test(lc)) hasMOQ = true;
      }
    } catch(e) {}
  }

  const realMsgs = customerMsgs + agentMsgs;
  const daysAgo = c.daysAgo;
  const country = c.country || '';
  const coreMarkets = ['SD','EG','CD','ZM','CI','SA','AE'];
  const isCore = coreMarkets.includes(country);

  // Enhanced tier calculation  
  let tier = c.priority; // Start with metadata tier
  let tierReason = '';

  // Upgrade signals
  if (hasPI && daysAgo < 7 && realMsgs > 5) { tier = 0; tierReason += 'PI/付款信号 '; }
  if (hasOrderSignal && daysAgo < 7) { tier = Math.min(tier, 0); tierReason += '下单信号 '; }
  if (hasAddress && hasPrice && daysAgo < 7 && realMsgs > 10) { tier = Math.min(tier, 0); tierReason += '选款+地址+报价 '; }
  if (customerMsgs > 20 && daysAgo < 2 && agentMsgs === 0) { tier = 0; tierReason += '客户大量回复未跟进 '; }
  if (realMsgs > 50 && daysAgo < 3) { tier = Math.min(tier, 0); tierReason += '高频对话近期活跃 '; }
