  if (hasPI && hasAddress && daysAgo < 14 && realMsgs > 5) { tier = 0; tierReason.push('PI+地址已确认'); }
  if (hasOrderSignal && daysAgo < 7 && realMsgs > 5) { tier = 0; tierReason.push('下单信号'); }
  if (customerMsgs >= 3 && lastCustomerMsgDays <= 1 && ourMsgs === 0) { tier = 0; tierReason.push('客户多条新消息未回'); }
  if (hasPrice && hasAddress && hasQuantity && daysAgo < 7) { tier = 0; tierReason.push('报价+地址+数量(近成交)'); }
  if (customerMsgs >= 100 && daysAgo < 3) { tier = 0; tierReason.push('大量客户消息近期活跃'); }
  if (realMsgs > 50 && daysAgo < 3 && customerMsgs > 20 && lastCustomerMsgDays <= 2) { tier = 0; tierReason.push('高频互动客户活跃'); }

  // P1 triggers
  if (hasPI && daysAgo < 14) { tier = Math.min(tier, 1); tierReason.push('PI相关'); }
  if (isCore && realMsgs > 10 && daysAgo < 5) { tier = Math.min(tier, 1); tierReason.push('核心市场活跃对话'); }
