  '133167278119-2500000853693_11011_icbu.json',
  '1507558069235-2500000853693_11011_icbu.json',
  '1507637510273-2500000853693_11011_icbu.json',
  '2500000853693-4500020103986_11011_icbu.json',
  '1507582644648-2500000853693_11011_icbu.json',
  '1507648744441-2500000853693_11011_icbu.json',
  '2500000853693-3500001141060_11011_icbu.json',
  '2500000853693-4500025203322_11011_icbu.json',
  '2500000853693-408052050936_11011_icbu.json',
  '133605767280-2500000853693_11011_icbu.json',
];

for (const tf of targets) {
  const fp = path.join(chatDir, tf);
  if (!fs.existsSync(fp)) { console.log('MISSING: ' + tf); continue; }

