    const msg = m.message || m;
    const uid = msg.sender && msg.sender.uid || '';
    const content = msg.content;
    if (isSys(content)) continue;
    const text = getText(content);
    if (!text.trim()) continue;
    const date = msg.createAt ? new Date(msg.createAt).toISOString().slice(0,16).replace('T',' ') : '';
    const who = uid === OUR_UID ? 'WE' : 'CUST';
    lines.push({ date, who, text: text.substring(0, 200) });
