cd "d:/ClaudeWorkspace/08_客户跟进/Okki" && node -e "
const fs = require('fs');
const path = require('path');
const ExcelJS = require('exceljs');

const DATA_DIR = path.join('data');
const REPORTS_DIR = path.join('reports');
const TM_FILE = path.join(DATA_DIR, 'tm_conversations_latest.json');
const CHAT_DIR = path.join(DATA_DIR, 'chat_history');
const CUSTOMERS_DIR = path.join(DATA_DIR, 'customers');
const STATE_FILE = 'STATE.md';

const NOW = new Date();
const NOW_TS = NOW.getTime();
const D = 86400000;
const DATE_STR = NOW.toISOString().slice(0, 10);
const TIME_STR = NOW.toISOString().slice(11, 16).replace(':','');

// Skip the full script, use enhanced data directly
const enhanced = JSON.parse(fs.readFileSync('data/s1_enhanced.json', 'utf8'));

// Read conversations for missing fields
const tmData = JSON.parse(fs.readFileSync(TM_FILE, 'utf8'));
const convs = tmData.conversations || [];

// Build lookup by name
const convByName = {};
for (const c of convs) {
  convByName[(c.name || '').toLowerCase().trim()] = c;
}

// For P3-P4, just add basic rows from metadata
const rows = [];
const processed = new Set();

// Add enhanced rows first (P0-P2 from our deep analysis)
for (const e of enhanced) {
  const daysAgo = Math.floor((NOW_TS - (convByName[e.name.toLowerCase()]?.lastContactTime || NOW_TS)) / D);
  const conv = convByName[e.name.toLowerCase()] || {};

  let stage = '';
  let bottleneck = '';
  let nextAction = '';
  let priority = '';

  if (e.tier === 0) {
    priority = '今天';
    // Add deep analysis results
    if (e.hasPI && e.hasAddress) {
      stage = 'PI已发/待付款';
      bottleneck = '等待客户付款确认';
      nextAction = '确认PI信息无误后提醒付款';
    } else if (e.hasOrderSignal && e.daysAgo < 3) {
      stage = '选款确认中';
      bottleneck = '款式/规格待最终确认';
      nextAction = '确认最终款式数量和地址';
    } else if (e.customerMsgs > 50) {
      stage = '高频互动中';
      bottleneck = '需确认当前卡点';
      nextAction = '回顾近期对话确认下一步';
    } else {
      stage = '报价已发';
      bottleneck = '等客户回应';
      nextAction = '24h内温和跟进';
    }
  } else if (e.tier === 1) {
    priority = '48h';
    stage = e.daysAgo < 3 ? '近期活跃' : '谈判中';
    nextAction = '48h内跟进';
  } else if (e.tier === 2) {
    priority = '本周';
    stage = '观察中';
    nextAction = '本周跟进';
  } else {
    priority = '';
    stage = '沉默->30d';
    nextAction = '';
  }

  const countryCN = {
    US:'美国', GH:'加纳', ZM:'赞比亚', CD:'刚果金', CI:'科特迪瓦', EG:'埃及', SA:'沙特', 
    TG:'多哥', ZA:'南非', BH:'巴林', OM:'阿曼', IN:'印度', IQ:'伊拉克', UK:'英国',
    AR:'阿根廷', KE:'肯尼亚', PK:'巴基斯坦', TZ:'坦桑尼亚', LB:'黎巴嫩', FR:'法国',
    ES:'西班牙', CN:'中国', AE:'阿联酋', SA:'沙特阿拉伯', ZM:'赞比亚'
  }[e.country] || e.country || '';

  rows.push({
    name: e.name,
    countryCN,
    tier: 'P' + e.tier,
    okkiLevel: '',
    okkiStatus: '',
    lastContactDays: e.daysAgo,
    lastContactDate: '',
    msgCount: e.msgCount,
    lastMsgDir: e.customerMsgs > 0 && e.lastCustomerMsgDays <= 1 ? '客户' : '我方',
    unreadCount: 0,
    stage,
    bottleneck,
    nextAction,
    followupPriority: priority,
    notes: (e.hasPI ? 'PI ':'') + (e.isCore ? '核心市场 ':'') + '客' + e.customerMsgs + '/' + e.realMsgs + '条',
    cid: e.cid,
    filename: e.filename,
  });
  processed.add(e.name.toLowerCase());
}

// Count tiers
const tc = { P0: 0, P1: 0, P2: 0, P3: 0, P4: 0 };
for (const e of enhanced) tc['P' + e.tier]++;

// Add P3-P4 from unmatched conversations
for (const conv of convs) {
  const nameLow = (conv.name || '').toLowerCase().trim();
  if (processed.has(nameLow)) continue;

  const days = conv.lastContactTime ? Math.floor((NOW_TS - conv.lastContactTime) / D) : 9999;
  let tier = 'P4';
  if (days < 30) tier = 'P3';
  tc[tier]++;

  const countryCN = {
    US:'美国', GH:'加纳', ZM:'赞比亚', CD:'刚果金', CI:'科特迪瓦', EG:'埃及', SA:'沙特'
  }[conv.complianceCountryCode || ''] || conv.complianceCountryCode || '';

  rows.push({
    name: conv.name || '',
    countryCN,
    tier,
    okkiLevel: '',
    okkiStatus: '',
    lastContactDays: days,
    lastContactDate: '',
    msgCount: 0,
    lastMsgDir: conv.latestMessage?.messageType === 'send' ? '我方' : '客户',
    unreadCount: conv.unreadCount || 0,
    stage: days > 30 ? '沉默->30d' : '',
    bottleneck: '',
    nextAction: '',
    followupPriority: '',
    notes: '',
    cid: conv.cid,
    filename: '',
  });
  processed.add(nameLow);
}

// Sort
const tierOrder = { P0: 0, P1: 1, P2: 2, P3: 3, P4: 4 };
rows.sort((a, b) => {
  const ta = tierOrder[a.tier] ?? 5;
  const tb = tierOrder[b.tier] ?? 5;
  if (ta !== tb) return ta - tb;
  return a.lastContactDays - b.lastContactDays;
});

// Generate Excel
const wb = new ExcelJS.Workbook();
const ws = wb.addWorksheet('客户管理看板', { views: [{ state: 'frozen', ySplit: 1 }] });

const cols = [
  { header: '客户名', key: 'name', width: 24 },
  { header: '国家', key: 'countryCN', width: 12 },
  { header: '梯队', key: 'tier', width: 7 },
  { header: '最后联系(天前)', key: 'lastContactDays', width: 11 },
  { header: '总消息', key: 'msgCount', width: 8 },
  { header: '最新', key: 'lastMsgDir', width: 7 },
  { header: '沟通阶段', key: 'stage', width: 18 },
  { header: '卡点', key: 'bottleneck', width: 28 },
  { header: '下一步行动', key: 'nextAction', width: 34 },
  { header: '跟紧', key: 'followupPriority', width: 8 },
  { header: '备注', key: 'notes', width: 28 },
];
ws.columns = cols;

const hr = ws.getRow(1);
hr.font = { bold: true, size: 11, color: { argb: 'FFFFFFFF' } };
hr.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FF2F5496' } };
hr.alignment = { vertical: 'middle', horizontal: 'center', wrapText: true };
hr.height = 34;

const tierFills = { P0: 'FFC00000', P1: 'FFED7D31', P2: 'FFFFC000', P3: 'FF4472C4', P4: 'FFA5A5A5' };

for (const row of rows) {
  const r = ws.addRow(row);
  r.height = 21;
  if (row.tier && tierFills[row.tier]) {
    const tc = r.getCell('tier');
    tc.font = { bold: true, color: { argb: 'FFFFFFFF' }, size: 11 };
    tc.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: tierFills[row.tier] } };
    tc.alignment = { horizontal: 'center' };
  }
  if (row.lastContactDays > 30) r.font = { color: { argb: 'FFA0A0A0' } };
  if (row.stage) r.getCell('stage').font = { bold: true };
  if (row.tier === 'P0') r.getCell('name').font = { bold: true };
}

ws.autoFilter = { from: { row: 1, column: 1 }, to: { row: rows.length + 1, column: cols.length } };

// Summary sheet
const sws = wb.addWorksheet('统计');
sws.columns = [
  { header: '指标', key: 'metric', width: 22 },
  { header: '数值', key: 'value', width: 26 },
];

const a24 = rows.filter(r => r.lastContactDays < 1).length;
const a7d = rows.filter(r => r.lastContactDays < 7).length;
const a30d = rows.filter(r => r.lastContactDays < 30).length;
const s30d = rows.filter(r => r.lastContactDays >= 30).length;

sws.addRows([
  { metric: '生成时间', value: NOW.toISOString().slice(0, 16).replace('T', ' ') },
  { metric: '客户总数', value: rows.length },
  { metric: '24h活跃', value: a24 },
  { metric: '7d活跃', value: a7d },
  { metric: '30d内活跃', value: a30d },
  { metric: '>30d沉默', value: s30d },
  { metric: '', value: '' },
  ...Object.entries(tc).map(([k, v]) => ({ metric: '梯队 ' + k, value: v })),
]);

const sh = sws.getRow(1);
sh.font = { bold: true, color: { argb: 'FFFFFFFF' } };
sh.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FF2F5496' } };

const outFile = path.join(REPORTS_DIR, '客户管理看板_' + DATE_STR + '_' + TIME_STR + '.xlsx');
await wb.xlsx.writeFile(outFile);

console.log('Generated:', outFile);
console.log('Tiers: P0=' + tc.P0 + ' P1=' + tc.P1 + ' P2=' + tc.P2 + ' P3=' + tc.P3 + ' P4=' + tc.P4);
console.log('24h:' + a24 + ' 7d:' + a7d + ' 30d:' + a30d + ' >30d:' + s30d);
" 2>&1

